name: Sync PR state to Linear

on:
  pull_request:
    types: [opened, reopened, ready_for_review, closed]

jobs:
  sync:
    runs-on: ubuntu-latest
    steps:
      - name: Sync matching Linear issue
        env:
          LINEAR_API_KEY: ${{ secrets.LINEAR_API_KEY }}
          PR_TITLE: ${{ github.event.pull_request.title }}
          PR_MERGED: ${{ github.event.pull_request.merged }}
          PR_ACTION: ${{ github.event.action }}
        run: |
          python3 - <<'PY'
          import json
          import os
          import re
          import sys
          import urllib.request

          api_key = os.getenv("LINEAR_API_KEY")
          if not api_key:
            print("LINEAR_API_KEY is not set.")
            sys.exit(1)

          pr_title = os.getenv("PR_TITLE", "")
          action = os.getenv("PR_ACTION", "")
          merged = os.getenv("PR_MERGED", "false").lower() == "true"

          # Keep this strict/safe: only act when the PR title contains a Linear key.
          match = re.search(r"\bLAF-\d+\b", pr_title)
          if not match:
            print(f"No Linear issue identifier found in PR title: {pr_title!r}. Skipping.")
            sys.exit(0)

          identifier = match.group(0)
          if action == "closed":
            if not merged:
              print("PR was closed without merge. Skipping.")
              sys.exit(0)
            target_state_type = "completed"
            target_state_name = "Done"
          else:
            target_state_type = "started"
            target_state_name = "In Progress"

          def linear_graphql(query: str, variables: dict):
            payload = json.dumps({"query": query, "variables": variables}).encode("utf-8")
            req = urllib.request.Request(
              "https://api.linear.app/graphql",
              data=payload,
              headers={
                "Authorization": api_key,
                "Content-Type": "application/json",
              },
              method="POST",
            )
            with urllib.request.urlopen(req) as resp:
              body = json.loads(resp.read().decode("utf-8"))
            if "errors" in body and body["errors"]:
              raise RuntimeError(f"Linear API error: {body['errors']}")
            return body["data"]

          issue_query = """
          query IssueByIdentifier($identifier: String!) {
            issues(filter: { identifier: { eq: $identifier } }) {
              nodes {
                id
                identifier
                team {
                  id
                  key
                  name
                  states {
                    nodes {
                      id
                      name
                      type
                    }
                  }
                }
              }
            }
          }
          """
          issue_data = linear_graphql(issue_query, {"identifier": identifier})
          issues = issue_data.get("issues", {}).get("nodes", [])
          if not issues:
            print(f"Linear issue {identifier} was not found.")
            sys.exit(1)

          issue = issues[0]
          states = issue["team"]["states"]["nodes"]

          # Prefer state `type` so IDs come from the real team workflow.
          target_state = next((s for s in states if s.get("type") == target_state_type), None)
          if not target_state:
            target_state = next((s for s in states if s.get("name", "").lower() == target_state_name.lower()), None)

          if not target_state:
            print(
              f"Could not find a '{target_state_name}' state for team {issue['team']['key']} "
              f"(looked for type='{target_state_type}' and name='{target_state_name}')."
            )
            sys.exit(1)

          update_mutation = """
          mutation UpdateIssueState($issueId: String!, $stateId: String!) {
            issueUpdate(id: $issueId, input: { stateId: $stateId }) {
              success
            }
          }
          """
          update_data = linear_graphql(
            update_mutation,
            {"issueId": issue["id"], "stateId": target_state["id"]},
          )
          success = update_data.get("issueUpdate", {}).get("success")
          if not success:
            print(f"Failed to update issue {identifier} to {target_state['name']}.")
            sys.exit(1)

          print(f"Updated {identifier} to '{target_state['name']}'.")
          PY

